def _dbt_column_process_to_nested(
    dbt_column_process: DbtColumnProcess,
) -> DbtColumnProcessNested:
    """Convert flat DbtColumnProcess to nested format."""
    attrs = DbtColumnProcessAttributes()
    _populate_dbt_column_process_attrs(attrs, dbt_column_process)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dbt_column_process,
        _DBT_COLUMN_PROCESS_REL_FIELDS,
        DbtColumnProcessRelationshipAttributes,
    )
    return DbtColumnProcessNested(
        guid=dbt_column_process.guid,
        type_name=dbt_column_process.type_name,
        status=dbt_column_process.status,
        version=dbt_column_process.version,
        create_time=dbt_column_process.create_time,
        update_time=dbt_column_process.update_time,
        created_by=dbt_column_process.created_by,
        updated_by=dbt_column_process.updated_by,
        classifications=dbt_column_process.classifications,
        classification_names=dbt_column_process.classification_names,
        meanings=dbt_column_process.meanings,
        labels=dbt_column_process.labels,
        business_attributes=dbt_column_process.business_attributes,
        custom_attributes=dbt_column_process.custom_attributes,
        pending_tasks=dbt_column_process.pending_tasks,
        proxy=dbt_column_process.proxy,
        is_incomplete=dbt_column_process.is_incomplete,
        provenance_type=dbt_column_process.provenance_type,
        home_id=dbt_column_process.home_id,
        depth=dbt_column_process.depth,
        immediate_upstream=dbt_column_process.immediate_upstream,
        immediate_downstream=dbt_column_process.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dbt_column_process_from_nested(nested: DbtColumnProcessNested) -> DbtColumnProcess:
    """Convert nested format to flat DbtColumnProcess."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DbtColumnProcessAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DBT_COLUMN_PROCESS_REL_FIELDS,
        DbtColumnProcessRelationshipAttributes,
    )
    return DbtColumnProcess(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_dbt_column_process_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dbt_column_process_to_nested_bytes(
    dbt_column_process: DbtColumnProcess, serde: Serde
) -> bytes:
    """Convert flat DbtColumnProcess to nested JSON bytes."""
    return serde.encode(_dbt_column_process_to_nested(dbt_column_process))


def _dbt_column_process_from_nested_bytes(
    data: bytes, serde: Serde
) -> DbtColumnProcess:
    """Convert nested JSON bytes to flat DbtColumnProcess."""
    nested = serde.decode(data, DbtColumnProcessNested)
    return _dbt_column_process_from_nested(nested)


